update tb_todo
set focus_time = 
  case 
    when focus_time is null or focus_time = 0 then #{focusTime,jdbcType=BIGINT}
    else focus_time + #{focusTime,jdbcType=BIGINT}
  end,
  update_time = now()
where id = #{id,jdbcType=BIGINT}

