select c.id as categoryId, c.name as categoryName, count(t.id) as sum from tb_todo t left join tb_category c on t.category_id = c.id where t.is_delete = 1
and DATE_FORMAT(t.create_time, '%Y-%m-%d') >= #{startDate}
and DATE_FORMAT(t.create_time, '%Y-%m-%d') <= #{endDate}
and c.id in
#{item,jdbcType=INTEGER}
group by c.id, c.name

select c.id as categoryId, c.name as categoryName, DATE_FORMAT(t.create_time, '%Y-%m-%d') as date, count(t.id) as sum from tb_todo t left join tb_category c on t.category_id = c.id where t.is_delete = 1
and DATE_FORMAT(t.create_time, '%Y-%m-%d') >= #{startDate}
and DATE_FORMAT(t.create_time, '%Y-%m-%d') <= #{endDate}
and c.id in
#{item,jdbcType=INTEGER}
group by c.id, c.name, DATE_FORMAT(t.create_time, '%Y-%m-%d') order by date, c.id
